using UnityEngine;
using Climbing;
using UnityEditor;

public class ForceClimbFix
{
    public static string Run()
    {
        ClimbController[] ccs = Object.FindObjectsOfType<ClimbController>();
        if (ccs.Length == 0) return "No ClimbControllers found in scene.";

        int count = 0;
        foreach (var cc in ccs)
        {
            SerializedObject so = new SerializedObject(cc);
            so.FindProperty("AutoSearchBones").boolValue = true;

            // Manually find and assign bones to be absolutely sure
            Animator anim = cc.GetComponent<Animator>();
            if (anim == null) anim = cc.GetComponentInChildren<Animator>();

            if (anim != null && anim.isHuman)
            {
                Transform lHand = anim.GetBoneTransform(HumanBodyBones.LeftHand);
                Transform rHand = anim.GetBoneTransform(HumanBodyBones.RightHand);
                Transform lFoot = anim.GetBoneTransform(HumanBodyBones.LeftFoot);
                Transform rFoot = anim.GetBoneTransform(HumanBodyBones.RightFoot);

                if (lHand) so.FindProperty("LHand").objectReferenceValue = lHand.gameObject;
                if (rHand) so.FindProperty("RHand").objectReferenceValue = rHand.gameObject;
                if (lFoot) so.FindProperty("LFoot").objectReferenceValue = lFoot.gameObject;
                if (rFoot) so.FindProperty("RFoot").objectReferenceValue = rFoot.gameObject;
            }

            so.ApplyModifiedProperties();
            EditorUtility.SetDirty(cc);
            count++;
        }

        return $"Successfully fixed {count} ClimbController(s) in the scene.";
    }
}
